def get_Char(msg):
    alpha = 'abcdefghijklmnopqrstuvwxyz'
    x = 0
    for ele in msg:
        x = x + ord(ele)
    y = x % 26
    for ele in alpha:
        if ord(ele) == y:
            return ele

def magic_square_test(matrix):
    total = sum(matrix[0])
    for i in matrix:
        if sum(i) != total:
            return False
    for j in list(map(list, zip(*matrix))):
        if sum(j) != total:
            return False
    if sum(matrix[0]) != sum(matrix[-1]) or sum(matrix[0]) != sum([matrix[j][j] for j in range(4)]):
        return False
    return True

def Find_Min_Length(L):
    minLength = len(L[0])
    for i in L:
        if len(i) < minLength:
            minLength = len(i)
    return minLength

def search(a):
    n = len(a)
    if n < 3:
        return a[0]
    for i in range(0, n, 3):
        if i + 2 < n and a[i] == a[i + 1] == a[i + 2]:
            continue
        return a[i]

import math

# This function finds the nth number in the Newman-Conway sequence
def sequence(n):
    if n == 1:
        return 1
    if n == 2:
        return 1
    else:
        nthNumber1 = n // math.ceil(math.sqrt(n))
        nthNumber2 = n // math.ceil(math.sqrt(n)) * (math.ceil(math.sqrt(n)) + nthNumber1) // 2 + max(n % math.ceil(math.sqrt(n)), 0)
        return nthNumber2 - nthNumber1 + 1

def pos_count(nums):
    count = 0
    for num in nums:
        if num > 0:
            count += 1
    return count

def common_in_nested_list(lsts):
    common_elements = set(lsts[0])
    for list in lsts:
        common_elements.intersection_update(list)

    return list(common_elements)

import math
from numba import njit

@njit
def bell_number(n: int) -> int:
    if n == 0:
        return 1

    result = 1
    prev = 1

    for i in range(1, n + 1):
        result = prev + int(math.factorial(n) // (math.factorial(n - i) * math.factorial(i) * 2 ** (n - i)))
        prev = result

    return result

def find_Max_Num(nums):
    nums_dict = {}
    for i in range(10):
        nums_dict[str(i)] = nums.count(str(i))

    temp = list(nums_dict.keys())
    temp.sort(reverse=True)
    result = 0
    for i in temp:
        while nums_dict[str(i)] != 0:
            result += int(i)
            nums_dict[str(i)] -= 1
            result *= 10
    return result // 10

def is_undulating(n):
    arr, prev = list(map(int, str(n))), 2
    if arr[0] == arr[1]:
        return False

    for i in range(1, len(arr)):
        if arr[i] == prev or arr[i] == 2 * prev - arr[i - 1] or arr[i] == 2 * arr[i - 1] - prev:
            prev = arr[i]
        else:
            return False

    return True

def add_lists(t, l):
    for x in t:
        l.append(x)
    return tuple(l)

from math import pi, sqrt

def volume_sphere(r):
    return {(pi * (sqrt(3) / 2)) * pow(r, 3): (12 * pi * r)}

def recursive_list_sum(lst):
    s = 0
    for item in lst:
        if isinstance(item, list):
            s += recursive_list_sum(item)
        else:
            s += item
    return s

def remove_dirty_chars(string1, string2):
    result = [i for i in string1 if i not in string2]
    return ''.join(result)

def max_product_tuple(tup_list):
    product = 1
    max_product = 0
    for i in range(len(tup_list)):
        product = tup_list[i][0] * tup_list[i][1]
        if product > max_product:
            max_product = product
    return max_product

def is_sublist(source, subset):
    for i in range(len(source) - len(subset) + 1):
        if source[i:i + len(subset)] == subset:
            return True
    return False

def is_octagonal(n):
    discriminant = 1 + 24 * n
    if discriminant < 0:
        return "False"

    number = [(-1 + discriminant ** (1 / 2)) / 6, (-1 - discriminant ** (1 / 2)) / 6]
    for i in number:
        if 1 == i.is_integer():
            return "True"
    return "False"

import re

def text_lowercase_underscore(test_str):
    return bool(re.search('^[a-z]+_[a-z]+$' + test_str))

def decimal_to_binary(n):
    arr = []
    x = n
    while x >= 0:
        if x % 2 == 1:
            arr.append('1')
            x = x - 1
        else:
            arr.append('0')
            x = x - 1
    arr.reverse()
    return ''.join(arr)

def is_Diff(n):
    odds = ''
    evens = ''
    for x in range(1, len(str(n))+1):
        if x % 2 == 0:
            evens += str(n)[-x:]
        else:
            odds += str(n)[-x:]
    return int(evens) - int(odds) % 11 == 0

def smallest_num(nums):
    cmin = nums[0]
    for num in nums:
        if num < cmin:
            cmin = num
    return cmin

def freq_count(a):
    d = {}
    for i in a:
        if i in d:
            d[i] = d[i] + 1
        else:
            d[i] = 1
    return d

