def amicable_numbers_sum(num):
    result = 0
    for i in range(1, num + 1):
        d = 1
        for j in range(2, int(i**0.5) + 1):
            if i % j == 0:
                d += 2 * j
                if i / j != j:
                    d -= i / j
        if d > i:
            d = d - i
        if d < i + 1 and i == sum_divisors(d):
            result += i
        if d == i:
            result += d
        print(result)
    return result

def sum_divisors(n):
    d = 1
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            d += i
            if i != n / i:
                d += n / i
    return d

def find_length(string):
    count = 0
    length = 0
    for i in range(len(string)):
        if string[i] == '1':
            count += 1
        elif string[i] == '0':
            length = max(length, count)
            count = 0
    length = max(length, count)
    return length

def dif_Square(A):
    A = abs(A)
    if A % 4 == 3 or A == 0:
        return True
    return False

def multiply_int(dividend, divisor):
    res = 0
    if divisor > 0:
        for i in range(divisor):
            res = res + dividend
    else:
        for i in range(-divisor):
            res = res - dividend
    return res

def merge_dictionaries_three(d3, d2, d1):
    d_val = d3.copy()
    d_val.update(d2)
    res = {**d_val, **d1}
    return res

def find_Volume(base, height, length):
    volume = 0.5 * base * height * length
    return volume
